const insertFeedTopics = `-- name: InsertFeedTopics :exec
INSERT INTO feed_topics (feed_id, topic_id)
SELECT $1::uuid, UNNEST($2::uuid[])
ON CONFLICT (feed_id, topic_id) DO NOTHING
`

type InsertFeedTopicsParams struct {
	FeedID   uuid.UUID   `json:"feed_id"`
	TopicIds []uuid.UUID `json:"topic_ids"`
}

// Bulk-insert feed↔topic associations. Caller passes a uuid[] of topic ids
// that all belong to the same feed. Runs inside the handler-supplied tx so
// partial writes roll back with the feed insert/update. ON CONFLICT DO
// NOTHING absorbs caller-side duplicates (same topic_id sent twice) without
// leaking 23505 as a 500 — idempotent per (feed_id, topic_id) pair.
func (q *Queries) InsertFeedTopics(ctx context.Context, arg InsertFeedTopicsParams) error {
	_, err := q.db.Exec(ctx, insertFeedTopics, arg.FeedID, arg.TopicIds)
	return err
}

